class Solution:
    def maximumLength(self, s: str) -> int:

        # Parse runs of each character
        runs = defaultdict(list)
        current_char = s[0]
        current_run = 1
        for c in s[1:]:
            if c == current_char:
                current_run += 1
            else:
                runs[current_char].append(current_run)
                current_char = c
                current_run = 1
        runs[current_char].append(current_run)

        # Determine maximum run length to check
        max_run = 0
        for c in runs:
            for r in runs[c]:
                if r > max_run:
                    max_run = r

        # Check for valid lengths in descending order
        for l in range(max_run, 0, -1):
            for c in runs:
                total = 0
                for r in runs[c]:
                    if r >= l:
                        total += (r - l + 1)
                if total >= 3:
                    return l

        return -1

